let rows: Vec<Row> = app.entries.iter().skip(app.scroll_offset).map(|e| { Row::new(vec![Cell::from(e.rank.to_string()), Cell::from(e.hotkey.replace(|c: char| !c.is_ascii(), "?")), Cell::from(e.github.replace(|c: char| !c.is_ascii(), "?")), Cell::from(format!("{:.2}", e.net_points)), Cell::from(e.valid.to_string()), Cell::from(e.invalid.to_string()), Cell::from(e.stars.to_string()), Cell::from(format!("{:.4}", e.weight)),])}).collect();